(function(){"use strict";onmessage=function(a){if(a.data.type==="START"){const t=a.data.tZero,e=setInterval(()=>{postMessage({relative_timestamp:Date.now()-t,ax:(Math.random()-.5)*4,ay:(Math.random()-.5)*4,az:(Math.random()-.5)*4,gx:(Math.random()-.5)*2,gy:(Math.random()-.5)*2,gz:(Math.random()-.5)*2})},20);self._intervalId=e}a.data.type==="STOP"&&(clearInterval(self._intervalId),self.close())}})();
